#!/usr/bin/env python3
"""Review saved path traversal, ACL, and permission-log evidence."""

from __future__ import annotations

import argparse
import re
from pathlib import Path


def read_optional(path: Path | None) -> str:
    if path is None:
        return ""
    try:
        return path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        raise SystemExit(f"error: cannot read {path}: {exc}") from exc


def main() -> int:
    parser = argparse.ArgumentParser(description="Review saved permission evidence.")
    parser.add_argument("--namei", type=Path)
    parser.add_argument("--acl", type=Path)
    parser.add_argument("--log", type=Path)
    parser.add_argument("--require-all", action="store_true")
    args = parser.parse_args()
    if not any((args.namei, args.acl, args.log)):
        parser.error("provide at least one of --namei, --acl, or --log")

    namei = read_optional(args.namei)
    acl = read_optional(args.acl)
    log = read_optional(args.log)
    signals = {
        "blocked_traversal": bool(re.search(r"^\s*d---------\s", namei, re.M)),
        "restrictive_acl_mask": "mask::r--" in acl and "effective:r--" in acl,
        "application_denied": bool(
            re.search(r"permission denied|operation not permitted|access denied", log, re.I)
        ),
    }

    for name, present in signals.items():
        print(f"{name}: {'present' if present else 'not observed'}")
    print("review: traversal, identity/group membership, ACL mask, and application evidence are distinct")

    if args.require_all:
        return 0 if all(signals.values()) else 1
    return 0 if any(signals.values()) else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Review saved Slurm job-record and output-path evidence."""

from __future__ import annotations

import argparse
import csv
import re
from pathlib import Path


def read(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        raise SystemExit(f"error: cannot read {path}: {exc}") from exc


def main() -> int:
    parser = argparse.ArgumentParser(description="Review saved Slurm output-log evidence.")
    parser.add_argument("--job-record", required=True, type=Path)
    parser.add_argument("--filesystem", required=True, type=Path)
    args = parser.parse_args()

    job_record = read(args.job_record)
    filesystem = read(args.filesystem)
    fields = {
        name: bool(re.search(rf"\b{name}=\S+", job_record))
        for name in ("WorkDir", "StdOut", "StdErr", "Command")
    }
    rows = list(csv.DictReader(filesystem.splitlines(), delimiter="|"))
    missing = [row for row in rows if row.get("exists") == "no"]
    empty = [
        row for row in rows if row.get("exists") == "yes" and row.get("size") == "0"
    ]

    for name, present in fields.items():
        print(f"job_record_{name.lower()}: {'present' if present else 'missing'}")
    print(f"missing_path_records: {len(missing)}")
    print(f"empty_file_records: {len(empty)}")
    print("review: resolve paths against WorkDir, then separate missing files from empty output")

    return 0 if all(fields.values()) and (missing or empty) else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Classify reasons in saved Slurm queue or job snapshots."""

from __future__ import annotations

import argparse
import re
from pathlib import Path


DETAIL_REASON_RE = re.compile(r"\bReason=([A-Za-z][A-Za-z0-9_]*)")
TABLE_REASON_RE = re.compile(r"\sPD\s.*\s\(?([A-Za-z][A-Za-z0-9_]*)\)?\s*$")


def reason_category(reason: str) -> str:
    if reason.startswith("Dependency"):
        return "dependency"
    if reason == "Priority":
        return "priority"
    if reason == "Resources":
        return "resources"
    if reason.startswith(("Assoc", "QOS", "Max")):
        return "policy-limit"
    if any(term in reason for term in ("Node", "Partition", "Reservation")):
        return "availability-or-policy"
    return "unclassified"


def extract_reasons(text: str) -> list[str]:
    reasons = DETAIL_REASON_RE.findall(text)
    for line in text.splitlines():
        match = TABLE_REASON_RE.search(line)
        if match:
            reasons.append(match.group(1))
    return list(dict.fromkeys(reasons))


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Classify reason fields in saved public-safe Slurm snapshots."
    )
    parser.add_argument("snapshots", nargs="+", type=Path)
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    missing_reason = False
    for path in args.snapshots:
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            print(f"error: cannot read {path}: {exc}")
            return 2

        reasons = extract_reasons(text)
        if not reasons:
            print(f"{path}: no pending reason found")
            missing_reason = True
            continue
        for reason in reasons:
            print(f"{path}: {reason} -> {reason_category(reason)}")

    print("review: reason classes are point-in-time evidence, not start-time promises")
    return 1 if missing_reason else 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Review saved Slurm queue and visible QOS/account policy evidence."""

from __future__ import annotations

import argparse
import re
from pathlib import Path


def read(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        raise SystemExit(f"error: cannot read {path}: {exc}") from exc


def classify(reason: str) -> str:
    if reason.startswith("AssocGrp"):
        return "association-aggregate-limit"
    if reason.startswith("AssocMax"):
        return "association-per-job-limit"
    if reason.startswith("QOSGrp"):
        return "qos-aggregate-limit"
    if reason.startswith("QOSMax"):
        return "qos-per-job-limit"
    if reason in {"InvalidAccount", "InvalidQOS"}:
        return "invalid-association-or-qos"
    if reason == "Priority":
        return "priority"
    return "unclassified"


def main() -> int:
    parser = argparse.ArgumentParser(description="Review saved Slurm QOS evidence.")
    parser.add_argument("--queue", required=True, type=Path)
    parser.add_argument("--policy", required=True, type=Path)
    args = parser.parse_args()

    queue = read(args.queue)
    policy = read(args.policy)
    reasons = re.findall(r"\sPD\s.*\s([A-Za-z][A-Za-z0-9_]*)\s*$", queue, re.M)
    reason = reasons[0] if reasons else ""
    policy_fields = {
        name: name in policy for name in ("Account", "QOS", "GrpTRES", "Fairshare")
    }

    print(f"pending_reason: {reason or 'missing'}")
    print(f"reason_category: {classify(reason) if reason else 'missing'}")
    for name, present in policy_fields.items():
        print(f"policy_{name.lower()}: {'present' if present else 'missing'}")
    print("review: visible policy fields are evidence, not a complete policy or start-time promise")

    return 0 if reason and all(policy_fields.values()) else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Small TensorFlow distributed strategy smoke test for Slurm jobs."""

from __future__ import annotations

import json
import os
import socket
import sys
from typing import Iterable


def getenv_int(name: str, default: int) -> int:
    value = os.environ.get(name)
    if value is None or value == "":
        return default
    try:
        return int(value)
    except ValueError:
        return default


def split_workers(value: str) -> list[str]:
    return [item.strip() for item in value.split(",") if item.strip()]


def configure_tf_config(workers: Iterable[str], task_index: int) -> None:
    worker_list = list(workers)
    if not worker_list or "TF_CONFIG" in os.environ:
        return
    os.environ["TF_CONFIG"] = json.dumps(
        {
            "cluster": {"worker": worker_list},
            "task": {"type": "worker", "index": task_index},
        }
    )


def main() -> int:
    workers = split_workers(os.environ.get("TF_WORKERS", ""))
    task_index = getenv_int("TF_TASK_INDEX", getenv_int("SLURM_PROCID", 0))
    configure_tf_config(workers, task_index)

    try:
        import tensorflow as tf
    except ImportError as exc:
        print(f"ERROR: TensorFlow import failed: {exc}", file=sys.stderr)
        return 2

    try:
        if len(workers) > 1:
            strategy = tf.distribute.MultiWorkerMirroredStrategy()
        else:
            strategy = tf.distribute.MirroredStrategy()
    except Exception as exc:
        print(f"ERROR: TensorFlow strategy initialization failed: {exc}", file=sys.stderr)
        return 3

    tf_config = os.environ.get("TF_CONFIG", "")
    physical_gpus = tf.config.list_physical_devices("GPU")
    logical_gpus = tf.config.list_logical_devices("GPU")
    worker_count = len(workers) if workers else 1

    print(
        "rank_report "
        f"host={socket.gethostname()} "
        f"task_index={task_index} worker_count={worker_count} "
        f"strategy={type(strategy).__name__} "
        f"replicas={strategy.num_replicas_in_sync} "
        f"physical_gpus={len(physical_gpus)} logical_gpus={len(logical_gpus)} "
        f"tf_version={tf.__version__} tf_config={tf_config}",
        flush=True,
    )

    try:
        with strategy.scope():
            per_replica = strategy.run(
                lambda: tf.constant(float(task_index + 1), dtype=tf.float32)
            )
            reduced = strategy.reduce(tf.distribute.ReduceOp.SUM, per_replica, axis=None)
            result = float(reduced.numpy())
    except Exception as exc:
        print(f"ERROR: TensorFlow tensor reduction failed: {exc}", file=sys.stderr)
        return 4

    if result <= 0.0:
        print(f"ERROR: unexpected reduction result={result}", file=sys.stderr)
        return 5

    print(
        f"task_index={task_index} reduction_result={result} status=ok",
        flush=True,
    )
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

